// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





const WEATHER_ICON_MAP: Record<string, string> = {
  sunny: '☀️',
  clear: '☀️',
  'partly cloudy': '⛅',
  cloudy: '☁️',
  overcast: '☁️',
  rainy: '🌧️',
  rain: '🌧️',
  drizzle: '🌦️',
  storm: '⛈️',
  thunderstorm: '⛈️',
  snow: '❄️',
  sleet: '🌨️',
  fog: '🌫️',
  mist: '🌫️',
  windy: '💨',
};

function normalizeCondition(condition: string): string {
  return condition.trim().toLowerCase();
}

function getWeatherEmoji(condition: string): string {
  const normalized = normalizeCondition(condition);
  if (WEATHER_ICON_MAP[normalized]) return WEATHER_ICON_MAP[normalized];
  const matchedKey = Object.keys(WEATHER_ICON_MAP).find((key) => normalized.includes(key));
  return matchedKey ? WEATHER_ICON_MAP[matchedKey] : '🌤️';
}

function formatForecastLabel(day?: string): string {
  if (!day) return '—';
  return day;
}

function formatTemp(value?: number, unit?: string): string {
  if (typeof value !== 'number' || Number.isNaN(value)) return '—';
  return `${Math.round(value)}°${unit || ''}`;
}

function getConditionTone(condition: string): {
  bg: string;
  border: string;
  text: string;
} {
  const normalized = normalizeCondition(condition);
  if (normalized.includes('rain') || normalized.includes('storm') || normalized.includes('drizzle')) {
    return {
      bg: 'var(--ggui-color-primary-50)',
      border: 'var(--ggui-color-primary-200)',
      text: 'var(--ggui-color-primary-800)',
    };
  }
  if (normalized.includes('snow') || normalized.includes('sleet')) {
    return {
      bg: 'var(--ggui-color-info-50)',
      border: 'var(--ggui-color-info-200)',
      text: 'var(--ggui-color-info-800)',
    };
  }
  if (normalized.includes('fog') || normalized.includes('mist')) {
    return {
      bg: 'var(--ggui-color-surfaceVariant)',
      border: 'var(--ggui-color-outlineVariant)',
      text: 'var(--ggui-color-onSurfaceVariant)',
    };
  }
  return {
    bg: 'var(--ggui-color-warning-50)',
    border: 'var(--ggui-color-warning-200)',
    text: 'var(--ggui-color-warning-800)',
  };
}

function ForecastItem(props: {
  day: string;
  icon: string;
  high?: number;
  low?: number;
  unit: string;
}) {
  return (
    <Box
      paddingY="var(--ggui-spacing-3)"
      paddingX="var(--ggui-spacing-2)"
      borderRadius="var(--ggui-shape-radius-md)"
      background="var(--ggui-color-surface)"
      style={{
        border: '1px solid var(--ggui-color-outlineVariant)',
        minWidth: '92px',
        flex: '1 1 92px',
      }}
    >
      <Stack gap="var(--ggui-spacing-2)" align="center">
        <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant)" align="center">
          {props.day}
        </Text>
        <Text
          as="span"
          aria-hidden="true"
          size="lg"
          style={{ fontSize: 'var(--ggui-font-size-xl)', lineHeight: 1 }}
        >
          {props.icon}
        </Text>
        <Row gap="var(--ggui-spacing-2)" justify="center" align="center">
          <Text variant="bodySmall" weight="semibold">
            {formatTemp(props.high, props.unit)}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            /
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            {formatTemp(props.low, props.unit)}
          </Text>
        </Row>
      </Stack>
    </Box>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const forecastItems = useMemo(() => (Array.isArray(props.forecast) ? props.forecast : []).slice(0, 5), [props.forecast]);
  const tone = useMemo(() => getConditionTone(props.condition), [props.condition]);
  const conditionEmoji = useMemo(() => getWeatherEmoji(props.condition), [props.condition]);
  const cityLabel = props.city || 'Current location';
  const conditionLabel = props.condition || 'Unknown conditions';
  const temperatureDisplay = formatTemp(props.temperature, props.unit);
  const humidityDisplay = `${Math.round(props.humidity)}%`;
  const windDisplay = `${Math.round(props.windSpeed)} ${props.unit === 'F' ? 'mph' : 'km/h'}`;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        radius="xl"
        border
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">
            <Row align="center" justify="between" wrap>
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                  Weather
                </Text>
                <Heading level={2}>{cityLabel}</Heading>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                  {conditionLabel}
                </Text>
              </Stack>
              <Box
                padding="var(--ggui-spacing-4)"
                background={tone.bg}
                borderRadius="var(--ggui-shape-radius-xl)"
                style={{ border: `1px solid ${tone.border}`, minWidth: '120px' }}
              >
                <Stack gap="var(--ggui-spacing-1)" align="center">
                  <Text as="span" aria-hidden="true" style={{ fontSize: 'var(--ggui-font-size-4xl)', lineHeight: 1 }}>
                    {conditionEmoji}
                  </Text>
                  <Text variant="caption" weight="semibold" color={tone.text} align="center">
                    {conditionLabel}
                  </Text>
                </Stack>
              </Box>
            </Row>

            <Row gap="var(--ggui-spacing-6)" wrap>
              <Box>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Temperature</Text>
                <Heading level={1} color="var(--ggui-color-primary-600)">{temperatureDisplay}</Heading>
              </Box>
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
                <Box
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{ border: '1px solid var(--ggui-color-outlineVariant)', minWidth: '140px' }}
                >
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                    <Text variant="bodyLarge" weight="semibold">{humidityDisplay}</Text>
                  </Stack>
                </Box>
                <Box
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{ border: '1px solid var(--ggui-color-outlineVariant)', minWidth: '140px' }}
                >
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                    <Text variant="bodyLarge" weight="semibold">{windDisplay}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Row>
          </Stack>

          <Divider margin="var(--ggui-spacing-2)" />

          <Stack gap="var(--ggui-spacing-3)">
            <Row align="center" justify="between">
              <Heading level={4}>5-Day Forecast</Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Daily highs and lows
              </Text>
            </Row>
            <Box
              padding="var(--ggui-spacing-1)"
              borderRadius="var(--ggui-shape-radius-lg)"
              background="var(--ggui-color-surface)"
              style={{ border: '1px solid var(--ggui-color-outlineVariant)', overflowX: 'auto' }}
            >
              <Row gap="var(--ggui-spacing-2)" wrap>
                {forecastItems.length > 0 ? (
                  forecastItems.map((item, index) => (
                    <ForecastItem
                      key={`${item.day || 'day'}-${index}`}
                      day={formatForecastLabel(item.day)}
                      icon={item.icon || getWeatherEmoji(props.condition)}
                      high={item.high}
                      low={item.low}
                      unit={props.unit}
                    />
                  ))
                ) : (
                  <Box padding="var(--ggui-spacing-4)">
                    <Text color="var(--ggui-color-onSurfaceVariant)">No forecast data available.</Text>
                  </Box>
                )}
              </Row>
            </Box>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
